172: func (api *LokiAPI) DataQuery(ctx context.Context, query lokiQuery, responseOpts ResponseOpts) (*backend.DataResponse, error) {
173: 	req, err := makeDataRequest(ctx, api.url, query)
174: 	if err != nil {
175: 		return nil, err
176: 	}
177: 
178: 	queryAttrs := []any{"start", query.Start, "end", query.End, "step", query.Step, "query", query.Expr, "queryType", query.QueryType, "direction", query.Direction, "maxLines", query.MaxLines, "supportingQueryType", query.SupportingQueryType, "lokiHost", req.URL.Host, "lokiPath", req.URL.Path}
179: 	api.log.Debug("Sending query to loki", queryAttrs...)
180: 	start := time.Now()
181: 	resp, err := api.client.Do(req)
182: 	if err != nil {
183: 		status := "error"
184: 		if errors.Is(err, context.Canceled) {
185: 			status = "cancelled"
186: 		}
187: 		lp := []any{"error", err, "status", status, "duration", time.Since(start), "stage", stageDatabaseRequest}
188: 		lp = append(lp, queryAttrs...)
189: 		if resp != nil {
190: 			lp = append(lp, "statusCode", resp.StatusCode)
191: 		}
192: 		api.log.Debug("Error received from Loki", lp...)
193: 		if backend.IsDownstreamHTTPError(err) {
194: 			err = backend.DownstreamError(err)
195: 		}
196: 		res := backend.ErrorResponseWithErrorSource(err)
197: 		return &res, nil
198: 	}
199: 
200: 	defer func() {
201: 		if err := resp.Body.Close(); err != nil {
202: 			api.log.Warn("Failed to close response body", "error", err)
203: 		}
204: 	}()
205: 
206: 	lp := []any{"duration", time.Since(start), "stage", stageDatabaseRequest, "statusCode", resp.StatusCode, "contentLength", resp.Header.Get("Content-Length")}
207: 	lp = append(lp, queryAttrs...)
208: 	if resp.StatusCode/100 != 2 {
209: 		err := readLokiError(resp.Body)
210: 		res := backend.DataResponse{
211: 			Error:       err,
212: 			ErrorSource: backend.ErrorSourceFromHTTPStatus(resp.StatusCode),
213: 			Status:      backend.Status(resp.StatusCode),
214: 		}
215: 		lp = append(lp, "status", "error", "error", err, "statusSource", res.ErrorSource)
216: 		api.log.Debug("Error received from Loki", lp...)
217: 		return &res, nil
218: 	} else {
219: 		lp = append(lp, "status", "ok")
220: 		api.log.Info("Response received from loki", lp...)
221: 	}
222: 
223: 	start = time.Now()
224: 	_, span := api.tracer.Start(ctx, "datasource.loki.parseResponse")
225: 	defer span.End()
226: 
227: 	iter := jsoniter.Parse(jsoniter.ConfigDefault, resp.Body, 1024)
228: 	res := converter.ReadPrometheusStyleResult(iter, converter.Options{})
229: 	res.Status = backend.Status(resp.StatusCode)
230: 
231: 	if res.Error != nil {
232: 		span.RecordError(res.Error)
233: 		span.SetStatus(codes.Error, res.Error.Error())
234: 		instrumentation.UpdatePluginParsingResponseDurationSeconds(ctx, time.Since(start), "error")
235: 		api.log.Debug("Error parsing response from loki", "error", res.Error, "duration", time.Since(start), "stage", stageParseResponse)
236: 		return nil, res.Error
237: 	}
238: 	instrumentation.UpdatePluginParsingResponseDurationSeconds(ctx, time.Since(start), "ok")
239: 	api.log.Info("Response parsed from loki", "duration", time.Since(start), "framesLength", len(res.Frames), "stage", stageParseResponse)
240: 
241: 	return &res, nil
242: }
