244: func makeRawRequest(ctx context.Context, lokiDsUrl string, resourcePath string) (*http.Request, error) {
245: 	lokiUrl, err := url.Parse(lokiDsUrl)
246: 	if err != nil {
247: 		return nil, err
248: 	}
249: 
250: 	resourceUrl, err := url.Parse(resourcePath)
251: 	if err != nil {
252: 		return nil, err
253: 	}
254: 
255: 	// we take the path and the query-string only
256: 	lokiUrl.RawQuery = resourceUrl.RawQuery
257: 	lokiUrl.Path = path.Join(lokiUrl.Path, resourceUrl.Path)
258: 
259: 	req, err := http.NewRequestWithContext(ctx, "GET", lokiUrl.String(), nil)
260: 
261: 	if err != nil {
262: 		return nil, err
263: 	}
264: 
265: 	setXScopeOrgIDHeader(req, ctx)
266: 
267: 	return req, nil
268: }
