336: func getSupportingQueryHeaderValue(supportingQueryType SupportingQueryType) string {
337: 	value := ""
338: 
339: 	// we need to map the SupportingQueryType to the actual header value. For
340: 	// legacy reasons we defined each value, such as "logsVolume" maps to the
341: 	// "logvolhist" header value to Loki. With #85123, even the value set in the
342: 	// frontend query can be passed as is to Loki.
343: 	switch supportingQueryType {
344: 	case SupportingQueryLogsVolume:
345: 		value = "logvolhist"
346: 	case SupportingQueryLogsSample:
347: 		value = "logsample"
348: 	case SupportingQueryDataSample:
349: 		value = "datasample"
350: 	case SupportingQueryInfiniteScroll:
351: 		value = "infinitescroll"
352: 	default:
353: 		value = string(supportingQueryType)
354: 	}
355: 
356: 	return value
357: }
